module RefModule (
    input clk,
    input set,
    input reset,
    input d,
    output reg q
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (reset)
            q <= 1'b0;
        else if (set)
            q <= 1'b1;
        else
            q <= d;
    end
endmodule
